private enum InitializationResult {
    case ok
    case contractVersionMismatch
    case apiChecksumMismatch
}
// Use a global variable to perform the versioning checks. Swift ensures that
// the code inside is only computed once.
private let initializationResult: InitializationResult = {
    // Get the bindings contract version from our ComponentInterface
    let bindings_contract_version = 30
    // Get the scaffolding contract version by calling the into the dylib
    let scaffolding_contract_version = ffi_aletheia_core_uniffi_contract_version()
    if bindings_contract_version != scaffolding_contract_version {
        return InitializationResult.contractVersionMismatch
    }
    if (uniffi_aletheia_core_checksum_method_aletheiacore_cancel_interpretation_stream() != 20127) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_aletheia_core_checksum_method_aletheiacore_choose_symbol() != 10745) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_aletheia_core_checksum_method_aletheiacore_complete_reading() != 64734) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_aletheia_core_checksum_method_aletheiacore_get_fallback_prompts() != 49675) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_aletheia_core_checksum_method_aletheiacore_get_user_state() != 31908) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_aletheia_core_checksum_method_aletheiacore_perform_reading() != 20296) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_aletheia_core_checksum_method_aletheiacore_poll_interpretation_stream() != 59188) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_aletheia_core_checksum_method_aletheiacore_request_interpretation() != 61584) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_aletheia_core_checksum_method_aletheiacore_seed_bundled_data() != 29940) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_aletheia_core_checksum_method_aletheiacore_set_ai_api_key() != 63012) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_aletheia_core_checksum_method_aletheiacore_start_interpretation_stream() != 47979) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_aletheia_core_checksum_constructor_aletheiacore_new() != 17923) {
        return InitializationResult.apiChecksumMismatch
    }

    return InitializationResult.ok
}()

// Make the ensure init function public so that other modules which have external type references to
// our types can call it.
public func uniffiEnsureAletheiaCoreInitialized() {
    switch initializationResult {
    case .ok:
        break
    case .contractVersionMismatch:
        fatalError("UniFFI contract version mismatch: try cleaning and rebuilding your project")
    case .apiChecksumMismatch:
        fatalError("UniFFI API checksum mismatch: try cleaning and rebuilding your project")
    }
}

